mapper.select:
select b.*,c.price,c.num,c.attribute,c.min_inventory,p.product_title,c.img,p.mch_id,m.name shopName from lkt_group_product as b left join lkt_configure as c on b.attr_id=c.id left join lkt_product_list as p on b.product_id=p.id left join lkt_mch m on m.id = p.mch_id
and b.is_delete = 0
limit #{pageStart},#{pageEnd}

SELECT a.id, a.store_id, a.group_title, a.attr_id, a.product_id, a.group_level, a.group_data, a.starttime, a.endtime, a.activity_no, a.g_status, a.is_show, a.is_delete, a.is_copy, a.platform_activities_id, a.mch_id, a.audit_status, a.reason, a.num, a.sales_volume, a.price, a.addtime, a.free_freight FROM ( SELECT a.*,ROW_NUMBER() over(partition by a.activity_no) AS top FROM lkt_group_product a, lkt_product_list b WHERE a.product_id=b.id and a.is_delete = 0 ) AS a
a.add_time ${add_time_sort},
limit #{pageStart},#{pageEnd}

mapper.sql:
and g.store_id = #{store_id}
and g.is_delete = 0
and g.platform_activities_id =0
and g.g_status = #{g_status}
and p.product_title like concat('%',#{product_title},'%')
